    <div class="popup-header ot-header" @mousedown="startDrag"><div class="popup-title">{{ otNumber }}</div><div class="popup-controls"><span class="material-icons" @click.stop="toggleExpand">{{ isExpanded ? 'fullscreen_exit' : 'fullscreen' }}</span><span class="material-icons" @click="$emit('close')">close</span></div></div>
