        <div v-show="activeTab === 'siniestros'" class="siniestros-box"><div><label>Nro EHS</label><input v-model="siniestro.nroEhs" /></div><div><label>Nro OI</label><input v-model="siniestro.nroOi" /></div><div class="siniestros-actions"><button class="btn-cyan-outline" @click="limpiarSiniestro">CANCELAR</button><button class="btn-cyan" @click="guardarSiniestro">ACEPTAR</button></div></div>
      </section>
