<script setup>
import { defineComponent, h, ref, watch } from 'vue'
import SubgrillaHistorialPopup from '../../popup/SubgrillaHistorialPopup.vue'
import FmConfirmDialog from '../../shared/FmConfirmDialog.vue'
import FmAlertDialog from '../../shared/FmAlertDialog.vue'
import { downloadExcel } from '../../../utils/excelExport.js'

const SimpleTable = defineComponent({ props: { columns: Array, rows: Array, empty: String, selectable: Boolean }, setup(props) { const toggleAll = (event) => props.rows.forEach((row) => { row.selected = event.target.checked }); const toggleRow = (row, event) => { row.selected = event.target.checked }; return () => h('div', { class: 'table-wrap' }, [h('table', { class: 'fm-grid' }, [h('thead', [h('tr', [(props.selectable ? h('th', { class: 'check-col' }, [h('input', { type: 'checkbox', checked: props.rows.length > 0 && props.rows.every((row) => row.selected), onChange: toggleAll })]) : null), ...props.columns.map(c => h('th', c.label))])]), h('tbody', props.rows.length ? props.rows.map((r, i) => h('tr', { key: i, class: r.selected ? 'selected' : '' }, [(props.selectable ? h('td', { class: 'check-col' }, [h('input', { type: 'checkbox', checked: !!r.selected, onChange: (event) => toggleRow(r, event) })]) : null), ...props.columns.map(c => h('td', r[c.field] || ''))])) : [h('tr', [h('td', { class: 'empty-row', colspan: props.columns.length + (props.selectable ? 1 : 0) }, props.empty || 'No hay resultados')])])])]) } })
const props = defineProps({ show: Boolean, otNumber: String })
defineEmits(['close'])
const tabs = [{ id: 'actividades', label: 'Actividades' }, { id: 'base', label: 'Base Instalada' }, { id: 'historial', label: 'Historial del domicilio' }, { id: 'materiales', label: 'Materiales' }, { id: 'siniestros', label: 'Siniestros' }]
const activeTab = ref('actividades'), isExpanded = ref(false), showSubgrilla = ref(false), selectedHistorial = ref(null), showValidateConfirm = ref(false), showMaterialsAlert = ref(false), showSaveAlert = ref(false)
const pos = ref({ x: 60, y: 60 }), isDragging = ref(false); let startX = 0, startY = 0, initialX = 0, initialY = 0
const actividadesCols = [{ field: 'cod', label: 'COD ACTIVIDAD' }, { field: 'actividad', label: 'ACTIVIDAD' }, { field: 'cantidad', label: 'CANTIDAD' }, { field: 'cmo', label: 'COD CMO' }, { field: 'descCmo', label: 'CMO' }]
const baseCols = [{ field: 'base', label: 'BASE INSTALADA' }, { field: 'modelo', label: 'MODELO' }, { field: 'serie', label: 'NRO SERIE' }]
