const resultCols = [{ field: 'cod', label: 'COD ACTIVIDAD' }, { field: 'actividad', label: 'ACTIVIDAD' }, { field: 'cantidad', label: 'CANTIDAD' }, { field: 'cmo', label: 'COD CMO' }, { field: 'descCmo', label: 'CMO' }, { field: 'regla', label: 'REGLA TIPO' }, { field: 'aplicada', label: 'REGLA APLICADA' }, { field: 'motivo', label: 'MOTIVO' }, { field: 'estado', label: 'ESTADO ACTIVO' }, { field: 'validada', label: 'VALIDADA' }, { field: 'accion', label: 'ACCION' }]
const actividades = ref([{ cod: '1285', actividad: 'Instalar Acometida HFC', cantidad: '1', cmo: '5021497', descCmo: 'INSTALACION DE ACOMETIDA DOMICILIARIA' }, { cod: '90014', actividad: 'Se instaló CM Internet y Telefonía', cantidad: '1', cmo: '0000001', descCmo: 'NO HAY CMO' }, { cod: '90000', actividad: 'Se instaló acometida', cantidad: '1', cmo: '0000001', descCmo: 'NO HAY CMO' }])
const baseInstalada = ref([]), materiales = ref([])
const historial = ref([{ ot: 'M00966068', creacion: '2026-06-10 17:10:02.0', cierre: '2026-06-13 12:04:01.0', acta: 'A2732', estado: 'Certificada', contra: 'NET AND WORK S.A.', red: 'N', actividades: [{ codigo: '1285', desc: 'Instalar Acometida HFC', cant: '1', ncnd: 'ND1045', est_ncnd: 'En Curso', est_act: 'S' }] }, { ot: 'M00981724', creacion: '2026-06-13 12:53:40.0', cierre: '2026-06-13 14:23:58.0', acta: 'A2732', estado: 'Certificada', contra: 'NET AND WORK S.A.', red: 'N', actividades: [{ codigo: '90014', desc: 'Se instaló CM Internet y Telefonía', cant: '1', ncnd: '', est_ncnd: '', est_act: 'N' }] }])
const resultantes = ref([{ selected: false, cod: '70501', actividad: 'ACOMETIDA SOLO INT', cantidad: '1', cmo: '5021495', descCmo: 'INST.D/ACOMETIDA HFC', regla: 'E3', aplicada: 'E3IX00001AR-70501', motivo: 'APLICACION DE REGLAS', estado: 'S', validada: 'N', accion: '' }, { selected: false, cod: '70502', actividad: 'VALIDACION ACOMETIDA', cantidad: '1', cmo: '5021496', descCmo: 'VALIDACION TECNICA HFC', regla: 'E4', aplicada: 'E4IX00001AR-70502', motivo: 'VALIDACION AUTOMATICA', estado: 'S', validada: 'N', accion: '' }])
const siniestro = ref({ nroEhs: '', nroOi: '' })
const consultarMateriales = () => { materiales.value = []; showMaterialsAlert.value = true }
const limpiarSiniestro = () => { siniestro.value = { nroEhs: '', nroOi: '' } }
const guardarSiniestro = () => { showSaveAlert.value = true }
const openHistorial = (hist) => { selectedHistorial.value = hist; showSubgrilla.value = true }
const exportHistorial = () => downloadExcel({ filename: 'historial_domicilio.xls', title: 'Historial domicilio', columns: [{ field: 'ot', label: 'NRO OT' }, { field: 'creacion', label: 'FECHA CREACION OT' }, { field: 'cierre', label: 'FECHA CIERRE' }, { field: 'acta', label: 'NRO ACTA' }, { field: 'estado', label: 'ESTADO ACTA' }, { field: 'contra', label: 'EMPRESA CONTRATISTA' }, { field: 'red', label: 'OT RED' }], rows: historial.value })
const confirmValidate = () => { showValidateConfirm.value = false; showSaveAlert.value = true }
const center = () => { pos.value = { x: Math.max((window.innerWidth - 1100) / 2, 12), y: Math.max((window.innerHeight - 650) / 2, 12) } }
const toggleExpand = () => { isExpanded.value = !isExpanded.value }
const startDrag = (e) => { if (isExpanded.value) return; isDragging.value = true; startX = e.clientX; startY = e.clientY; initialX = pos.value.x; initialY = pos.value.y; document.addEventListener('mousemove', onDrag); document.addEventListener('mouseup', stopDrag) }
const onDrag = (e) => { if (!isDragging.value) return; pos.value.x = initialX + e.clientX - startX; pos.value.y = initialY + e.clientY - startY }
const stopDrag = () => { isDragging.value = false; document.removeEventListener('mousemove', onDrag); document.removeEventListener('mouseup', stopDrag) }
watch(() => props.show, (value) => { if (value) { center(); activeTab.value = 'actividades'; isExpanded.value = false } })
</script>

