er; gap: 14px; }.popup-actions { display: flex; justify-content: flex-end; gap: 10px; padding: 12px 18px; background: #fff; }.btn-cyan, .btn-cyan-outline { border-radius: 18px; padding: 8px 18px; font-weight: 800; cursor: pointer; }.btn-cyan { background: #00a9bd; border: 1px solid #00a9bd; color: #fff; }.btn-cyan-outline { background: #fff; border: 1px solid #00a9bd; color: #00a9bd; }@media (max-width: 900px) { .ot-info, .siniestros-box { grid-template-columns: repeat(2, minmax(180px, 1fr)); } .popup-actions, .section-title { flex-direction: column; align-items: stretch; } }@media (max-width: 560px) { .ot-info, .siniestros-box { grid-template-columns: 1fr; } .btn-cyan, .btn-cyan-outline { width: 100%; } }
</style>
